parameters.jsCode:
const body = $input.first().json.body ?? $input.first().json;
const now = new Date();
const windowStart = new Date(now.getTime() - 30 * 60 * 1000).toISOString();

let analysis = {};
try { analysis = typeof body.analysis === 'string' ? JSON.parse(body.analysis) : (body.analysis ?? {}); } catch(e) {}

return [{
  json: {
    incident_id: `INC-${Date.now()}`,
    source: body.source ?? 'unknown',
    received_at: now.toISOString(),
    window_start: windowStart,
    analysis,
    service: analysis.service ?? body.service ?? 'unknown',
    severity: analysis.severity ?? body.severity ?? 'unknown',
    alerts: body.alerts ? (typeof body.alerts === 'string' ? JSON.parse(body.alerts) : body.alerts) : [],
    metrics: body.metrics ? (typeof body.metrics === 'string' ? JSON.parse(body.metrics) : body.metrics) : {}
  }
}];

const aiRaw = $('AI - Generate RCA').first().json.message?.content ?? '{}';
const incidentCtx = $('Prepare Incident Context').first().json;

let rca;
try {
  rca = JSON.parse(aiRaw.replace(/```json|```/g, '').trim());
} catch(e) {
  rca = {
    incident_title: 'RCA Parse Error — Manual Review Required',
    root_cause: 'AI response could not be parsed',
    contributing_factors: [],
    impact: 'Unknown',
    timeline: [],
    immediate_actions: ['Review raw logs manually', 'Check Prometheus dashboards'],
    remediation_steps: [],
    prevention: [],
    estimated_mttr_minutes: 60
  };
}

return [{ json: {
  ...rca,
  incident_id: incidentCtx.incident_id,
  service: incidentCtx.service,
  severity: incidentCtx.severity,
  generated_at: new Date().toISOString()
}}];

parameters.jsonBody:
={
  "blocks": [
    { "type": "header", "text": { "type": "plain_text", "text": "🔍 RCA Ready — " + $json.incident_id } },
    { "type": "section", "text": { "type": "mrkdwn", "text": "*" + $json.incident_title + "*" } },
    {
      "type": "section",
      "fields": [
        { "type": "mrkdwn", "text": "*Service:*\n" + $json.service },
        { "type": "mrkdwn", "text": "*Severity:*\n" + $json.severity },
        { "type": "mrkdwn", "text": "*Est. MTTR:*\n" + $json.estimated_mttr_minutes + " min" },
        { "type": "mrkdwn", "text": "*Impact:*\n" + $json.impact }
      ]
    },
    { "type": "section", "text": { "type": "mrkdwn", "text": "*Root Cause:*\n" + $json.root_cause } },
    { "type": "section", "text": { "type": "mrkdwn", "text": "*Immediate Actions:*\n" + $json.immediate_actions.map((a, i) => (i+1) + '. ' + a).join('\n') } },
    { "type": "divider" },
    { "type": "context", "elements": [{ "type": "mrkdwn", "text": "Generated at " + $json.generated_at + " by AI-Ops Watchdog" }] }
  ]
}
